class QueryBuilder:
    def __init__(self):
        self._table = ''
        self._where = []
        self._limit = None
    def table(self, name):
        self._table = name
        return self
    def where(self, condition):
        self._where.append(condition)
        return self
    def limit(self, n):
        self._limit = n
        return self
    def build(self):
        return f'SELECT * FROM {self._table} WHERE {" AND ".join(self._where)} LIMIT {self._limit}'

