class SQLBuilder {
    private _select = '*';
    private _from = '';
    private _where: string[] = [];
    private _limit = 0;

    select(fields: string) { this._select = fields; return this; }
    from(table: string) { this._from = table; return this; }
    where(cond: string) { this._where.push(cond); return this; }
    limit(n: number) { this._limit = n; return this; }

    build(): string {
        let sql = `SELECT ${this._select} FROM ${this._from}`;
        if (this._where.length) sql += ` WHERE ${this._where.join(' AND ')}`;
        if (this._limit) sql += ` LIMIT ${this._limit}`;
        return sql;
    }
}

class HtmlBuilder {
    private root: string;
    private children: string[] = [];

    constructor(tag: string) {
        this.root = tag;
    }
    addChild(tag: string, content: string) {
        this.children.push(`<${tag}>${content}</${tag}>`);
        return this;
    }
    build(): string {
        return `<${this.root}>${this.children.join('')}</${this.root}>`;
    }
}

const html = new HtmlBuilder('div')
    .addChild('h1', '标题')
    .addChild('p', '内容')
