type AsyncStep<T> = (data: T) => Promise<T>;

class AsyncPipeline<T> {
    private steps: AsyncStep<T>[] = [];

    pipe(step: AsyncStep<T>) {
        this.steps.push(step);
        return this;
    }

    async execute(data: T): Promise<T> {
        let result = data;
        for (const step of this.steps) {
            result = await step(result);
        }
        return result;
    }
}

