type SafeStep<T> = (data: T) => T | Promise<T>;

class SafePipeline<T> {
    private steps: SafeStep<T>[] = [];
    private errorHandler: ((err: Error, data: T) => T) | null = null;

    pipe(step: SafeStep<T>) { this.steps.push(step); return this; }
    onError(handler: (err: Error, data: T) => T) { this.errorHandler = handler; return this; }

    async execute(data: T): Promise<T> {
        let result = data;
        for (const step of this.steps) {
            try {
                result = await step(result);
            } catch (err) {
                if (this.errorHandler) result = this.errorHandler(err as Error, result);
                else throw err;
            }
        }
        return result;
    }
}

