abstract class BaseRepository<T extends { id: string }> {
    protected items: T[] = [];

    async findById(id: string) {
        return this.items.find(i => i.id === id) || null;
    }
    async findAll() { return [...this.items]; }
    async save(entity: T) {
        const idx = this.items.findIndex(i => i.id === entity.id);
        if (idx >= 0) this.items[idx] = entity;
        else this.items.push(entity);
    }
    async delete(id: string) {
        this.items = this.items.filter(i => i.id !== id);
    }
}

class ArticleRepository extends BaseRepository<Article> {
    async findByAuthor(authorId: string) {
        return this.items.filter(a => a.authorId === authorId);
    }
}

