    if order['status'] == 'pending':
        if order['payment'] == 'paid':
            if order['stock'] > 0:
                order['status'] = 'confirmed'
                send_email(order['email'])
                update_stock(order['item_id'])
                log_order(order)
            else:
                order['status'] = 'out_of_stock'
        else:
