class UnitOfWork:
    def __init__(self, session_factory):
        self.session_factory = session_factory
        self._new = []
        self._dirty = []
        self._removed = []

    def __enter__(self):
        self.session = self.session_factory()
        return self

    def __exit__(self, *args):
        self.rollback()

    def commit(self):
        self.session.add_all(self._new)
        self.session.commit()
        self._new, self._dirty, self._removed = [], [], []

class CachedRepository:
    def __init__(self, repo, cache_client):
        self.repo = repo
        self.cache = cache_client

    async def get_by_id(self, entity_id: str):
        cache_key = f'{self.repo.entity_name}:{entity_id}'
        cached = await self.cache.get(cache_key)
        if cached:
            return deserialize(cached)
        entity = await self.repo.get_by_id(entity_id)
        if entity:
            await self.cache.set(cache_key, serialize(entity), ttl=300)
        return entity

import re

def sanitize_input(user_input: str) -> str:
    dangerous_patterns = [
        r'ignore.*previous.*instructions',
        r'you are now.*',
        r'system:\s*',
    ]
    for pattern in dangerous_patterns:
        if re.search(pattern, user_input, re.IGNORECASE):
            raise ValueError('Potentially malicious input detected')
    return f'---USER_INPUT---\n{user_input}\n---END---'

