class ConditionalPipeline<T> {
    private steps: { condition: (data: T) => boolean; step: Step<T> }[] = [];

    pipeWhen(condition: (data: T) => boolean, step: Step<T>) {
        this.steps.push({ condition, step });
        return this;
    }

    execute(data: T): T {
        return this.steps.reduce((acc, { condition, step }) => {
            return condition(acc) ? step(acc) : acc;
        }, data);
    }
}

